/*
 * Matyas-Meyer-Oseas hash function as specified in Zigbee spec.
 * Used to derive link key from install code.
 */
static zigbee_error_t zigbee_mmo_hash(const uint8_t *input, size_t input_len,
                                       uint8_t output[16])
{
    uint8_t hash[16];
    uint8_t temp[16];
    uint8_t block[16];
    size_t remaining = input_len;
    size_t offset = 0;

    memset(hash, 0, 16);

    /* Process full blocks */
    while (remaining >= 16) {
        memcpy(block, input + offset, 16);

        aes128_encrypt_block(hash, block, temp);

        for (int i = 0; i < 16; i++) {
            hash[i] = temp[i] ^ block[i];
        }

        offset += 16;
        remaining -= 16;
    }

    /* Process final block with padding */
    memset(block, 0, 16);
    if (remaining > 0) {
        memcpy(block, input + offset, remaining);
    }
    block[remaining] = 0x80;

    /* If there's room for the length in this block */
    if (remaining < 14) {
        uint16_t bit_len = (uint16_t)(input_len * 8);
        block[14] = (uint8_t)(bit_len >> 8);
        block[15] = (uint8_t)(bit_len & 0xFF);

        aes128_encrypt_block(hash, block, temp);
        for (int i = 0; i < 16; i++) {
            hash[i] = temp[i] ^ block[i];
        }
    } else {
        /* Need an extra block for length */
        aes128_encrypt_block(hash, block, temp);
        for (int i = 0; i < 16; i++) {
            hash[i] = temp[i] ^ block[i];
        }

        memset(block, 0, 16);
        uint16_t bit_len = (uint16_t)(input_len * 8);
        block[14] = (uint8_t)(bit_len >> 8);
        block[15] = (uint8_t)(bit_len & 0xFF);

        aes128_encrypt_block(hash, block, temp);
        for (int i = 0; i < 16; i++) {
            hash[i] = temp[i] ^ block[i];
        }
    }

    memcpy(output, hash, 16);
    zigbee_secure_memzero(temp, sizeof(temp));
    zigbee_secure_memzero(block, sizeof(block));

    return ZB_SUCCESS;
}

