/* ============================================================
 * Security Initialization
 * ============================================================ */

static zigbee_error_t zigbee_security_init(zigbee_device_context_t *ctx)
{
    if (ctx == NULL) {
        return ZB_ERR_INVALID_PARAM;
    }

    zigbee_log("INFO", "Initializing security subsystem");

    /* Set security level to AES-CCM-128 (highest) */
    ctx->trust_center.security_level = SECURITY_LEVEL_AES_CCM_128;

    /* Prefer install code based commissioning */
    ctx->commission_method = COMMISSION_INSTALL_CODE;
    ctx->trust_center.require_install_codes = true;
    ctx->trust_center.use_global_link_key = false;

    /* Initialize frame counters to prevent replay attacks */
    ctx->trust_center.trust_center_link_key.frame_counter = 0;
    ctx->trust_center.trust_center_link_key.sequence_number = 0;
    ctx->trust_center.network_key.frame_counter = 0;
    ctx->trust_center.network_key.sequence_number = 0;

    /* Set key rotation interval (24 hours in seconds) */
    ctx->trust_center.key_rotation_interval = 86400;
    ctx->trust_center.last_key_rotation = (uint32_t)time(NULL);

    /* If we have an install code, derive the link key from it */
    if (ctx->install_code.is_valid) {
        zigbee_error_t err = zigbee_derive_link_key_from_install_code(
            &ctx->install_code,
            ctx->trust_center.trust_center_link_key.key_data);

        if (err != ZB_SUCCESS) {
            zigbee_log("ERROR", "Failed to derive link key from install code");
            return err;
        }

        ctx->trust_center.trust_center_link_key.key_type = KEY_TYPE_INSTALL_CODE_DERIVED;
        ctx->trust_center.trust_center_link_key.is_valid = true;
        ctx->trust_center.trust_center_link_key.creation_time = time(NULL);

        zigbee_log("SECURITY", "Using install-code-derived link key for joining");
    } else {
        /*
         * Fallback: Use the well-known default TC link key for initial joining.
         * This is less secure but required for interoperability when install
         * codes are not available. The key MUST be replaced with a unique
         * key during the trust center key exchange after joining.
         */
        zigbee_log("SECURITY",
                   "WARNING: No install code available, using default TC link key for initial join");
        zigbee_log("SECURITY",
                   "A unique link key MUST be established after joining");

        memcpy(ctx->trust_center.trust_center_link_key.key_data,
               ZIGBEE_DEFAULT_TC_LINK_KEY, 16);
        ctx->trust_center.trust_center_link_key.key_type = KEY_TYPE_TRUST_CENTER_LINK;
        ctx->trust_center.trust_center_link_key.is_valid = true;
        ctx->trust_center.trust_center_link_key.creation_time = time(NULL);
        /* Mark for mandatory replacement */
        ctx->trust_center.use_global_link_key = true;
    }

    zigbee_log("INFO", "Security subsystem initialized");
    return ZB_SUCCESS;
}

